body:
Lowered memories are not being randomly initialized and begin simulation with the value `x`. This problem can be seen using a test file in the repo `test/firtool/memory.fir`; SFC has the following initialization logic which is missing in MFC:
```verilog
`ifdef RANDOMIZE_MEM_INIT
  _RAND_0 = {1{`RANDOM}};
  for (initvar = 0; initvar < 16; initvar = initvar+1)
    memory[initvar] = _RAND_0[7:0];
`endif // RANDOMIZE_MEM_INIT
`ifdef RANDOMIZE_REG_INIT
  _RAND_1 = {1{`RANDOM}};
  memory_r_en_pipe_0 = _RAND_1[0:0];
  _RAND_2 = {1{`RANDOM}};
  memory_r_addr_pipe_0 = _RAND_2[3:0];
  _RAND_3 = {1{`RANDOM}};
  memory_rw_r_en_pipe_0 = _RAND_3[0:0];
  _RAND_4 = {1{`RANDOM}};
  memory_rw_r_addr_pipe_0 = _RAND_4[3:0];
`endif // RANDOMIZE_REG_INIT
```


The entire example is:
```
circuit Qux:
  module Qux:
    input clock: Clock
    input rAddr: UInt<4>
    input rEn: UInt<1>
    output rData: UInt<8>
    input wAddr: UInt<4>
    input wEn: UInt<1>
    input wMask: UInt<1>
    input wData: UInt<8>
    input rwEn: UInt<1>
    input rwMode: UInt<1>
    input rwAddr: UInt<4>
    input rwMask: UInt<1>
    input rwDataIn: UInt<8>
    output rwDataOut: UInt<8>

    mem memory:
      data-type => UInt<8>
      depth => 16
      reader => r
      writer => w
      readwriter => rw
      read-latency => 1
      write-latency => 1
      read-under-write => undefined

    ; All of these are unified together
    memory.r.clk <= clock
    memory.r.en <= rEn
    memory.r.addr <= rAddr
    ; This is split
    rData <= memory.r.data

    ; All of these are unified together
    memory.w.clk <= clock
    memory.w.en <= wEn
    memory.w.addr <= wAddr
    ; These two are split
    memory.w.mask <= wMask
    memory.w.data <= wData

    ; All of these are unified together
    memory.rw.clk <= clock
    memory.rw.en <= rwEn
    memory.rw.addr <= rwAddr
    memory.rw.wmode <= rwMode
    ; All of these are split
    memory.rw.wmask <= rwMask
    memory.rw.wdata <= rwDataIn
    rwDataOut <= memory.rw.rdata


```

MFC produces:
```verilog
module memory_ext(	// ./test.fir:18:5
  input  [3:0] R0_addr,
  input        R0_en, R0_clk,
  input  [3:0] RW0_addr,
  input        RW0_en, RW0_clk, RW0_wmode,
  input  [7:0] RW0_wdata,
  input  [3:0] W0_addr,
  input        W0_en, W0_clk,
  input  [7:0] W0_data,
  output [7:0] R0_data, RW0_rdata);

  reg [7:0] Memory[0:15];
  reg       _GEN;
  reg [3:0] _GEN_0;

  always @(posedge R0_clk) begin
    _GEN <= R0_en;
    _GEN_0 <= R0_addr;
  end // always @(posedge)
  always @(posedge RW0_clk) begin
    if (RW0_en & RW0_wmode)
      Memory[RW0_addr] <= RW0_wdata;
  end // always @(posedge)
  always @(posedge W0_clk) begin
    if (W0_en)
      Memory[W0_addr] <= W0_data;
  end // always @(posedge)
  assign R0_data = _GEN ? Memory[_GEN_0] : 8'bx;	// ./test.fir:18:5
  assign RW0_rdata = RW0_en & ~RW0_wmode ? Memory[RW0_addr] : 8'bx;	// ./test.fir:18:5
endmodule
```

SFC produces:
```verilog
module Qux(
  input        clock,
  input  [3:0] rAddr,
  input        rEn,
  output [7:0] rData,
  input  [3:0] wAddr,
  input        wEn,
  input        wMask,
  input  [7:0] wData,
  input        rwEn,
  input        rwMode,
  input  [3:0] rwAddr,
  input        rwMask,
  input  [7:0] rwDataIn,
  output [7:0] rwDataOut
);
`ifdef RANDOMIZE_MEM_INIT
  reg [31:0] _RAND_0;
`endif // RANDOMIZE_MEM_INIT
`ifdef RANDOMIZE_REG_INIT
  reg [31:0] _RAND_1;
  reg [31:0] _RAND_2;
  reg [31:0] _RAND_3;
  reg [31:0] _RAND_4;
`endif // RANDOMIZE_REG_INIT
  reg [7:0] memory [0:15];
  wire  memory_r_en;
  wire [3:0] memory_r_addr;
  wire [7:0] memory_r_data;
  wire  memory_rw_r_en;
  wire [3:0] memory_rw_r_addr;
  wire [7:0] memory_rw_r_data;
  wire [7:0] memory_w_data;
  wire [3:0] memory_w_addr;
  wire  memory_w_mask;
  wire  memory_w_en;
  wire [7:0] memory_rw_w_data;
  wire [3:0] memory_rw_w_addr;
  wire  memory_rw_w_mask;
  wire  memory_rw_w_en;
  reg  memory_r_en_pipe_0;
  reg [3:0] memory_r_addr_pipe_0;
  reg  memory_rw_r_en_pipe_0;
  reg [3:0] memory_rw_r_addr_pipe_0;
  assign memory_r_en = memory_r_en_pipe_0;
  assign memory_r_addr = memory_r_addr_pipe_0;
  assign memory_r_data = memory[memory_r_addr];
  assign memory_rw_r_en = memory_rw_r_en_pipe_0;
  assign memory_rw_r_addr = memory_rw_r_addr_pipe_0;
  assign memory_rw_r_data = memory[memory_rw_r_addr];
  assign memory_w_data = wData;
  assign memory_w_addr = wAddr;
  assign memory_w_mask = wMask;
  assign memory_w_en = wEn;
  assign memory_rw_w_data = rwDataIn;
  assign memory_rw_w_addr = rwAddr;
  assign memory_rw_w_mask = rwMask;
  assign memory_rw_w_en = rwEn & rwMode;
  assign rData = memory_r_data;
  assign rwDataOut = memory_rw_r_data;
  always @(posedge clock) begin
    if (memory_w_en & memory_w_mask) begin
      memory[memory_w_addr] <= memory_w_data;
    end
    if (memory_rw_w_en & memory_rw_w_mask) begin
      memory[memory_rw_w_addr] <= memory_rw_w_data;
    end
    memory_r_en_pipe_0 <= rEn;
    if (rEn) begin
      memory_r_addr_pipe_0 <= rAddr;
    end
    memory_rw_r_en_pipe_0 <= rwEn & ~rwMode;
    if (rwEn & ~rwMode) begin
      memory_rw_r_addr_pipe_0 <= rwAddr;
    end
  end
// Register and memory initialization
`ifdef RANDOMIZE_GARBAGE_ASSIGN
`define RANDOMIZE
`endif
`ifdef RANDOMIZE_INVALID_ASSIGN
`define RANDOMIZE
`endif
`ifdef RANDOMIZE_REG_INIT
`define RANDOMIZE
`endif
`ifdef RANDOMIZE_MEM_INIT
`define RANDOMIZE
`endif
`ifndef RANDOM
`define RANDOM $random
`endif
`ifdef RANDOMIZE_MEM_INIT
  integer initvar;
`endif
`ifndef SYNTHESIS
`ifdef FIRRTL_BEFORE_INITIAL
`FIRRTL_BEFORE_INITIAL
`endif
initial begin
  `ifdef RANDOMIZE
    `ifdef INIT_RANDOM
      `INIT_RANDOM
    `endif
    `ifndef VERILATOR
      `ifdef RANDOMIZE_DELAY
        #`RANDOMIZE_DELAY begin end
      `else
        #0.002 begin end
      `endif
    `endif
`ifdef RANDOMIZE_MEM_INIT
  _RAND_0 = {1{`RANDOM}};
  for (initvar = 0; initvar < 16; initvar = initvar+1)
    memory[initvar] = _RAND_0[7:0];
`endif // RANDOMIZE_MEM_INIT
`ifdef RANDOMIZE_REG_INIT
  _RAND_1 = {1{`RANDOM}};
  memory_r_en_pipe_0 = _RAND_1[0:0];
  _RAND_2 = {1{`RANDOM}};
  memory_r_addr_pipe_0 = _RAND_2[3:0];
  _RAND_3 = {1{`RANDOM}};
  memory_rw_r_en_pipe_0 = _RAND_3[0:0];
  _RAND_4 = {1{`RANDOM}};
  memory_rw_r_addr_pipe_0 = _RAND_4[3:0];
`endif // RANDOMIZE_REG_INIT
  `endif // RANDOMIZE
end // initial
`ifdef FIRRTL_AFTER_INITIAL
`FIRRTL_AFTER_INITIAL
`endif
`endif // SYNTHESIS
endmodule
```
